    13→  });
    14→
    15→  describe('initial state', () => {
    16→    it('should have correct initial values', () => {
    17→      expect(slice.airlineMiles.redirectURL).toBe('');
    18→      expect(slice.airlineMiles.isLoading).toBe(false);
    19→      expect(slice.airlineMiles.isError).toBe(false);
    20→      expect(slice.airlineMiles.errorMessage).toBe('');
    21→    });
    22→  });
    23→
    24→  describe('actions', () => {
    25→    it('should set loading state', () => {
    26→      slice.airlineMilesActions.setLoading(true);
    27→
    28→      expect(mockSet).toHaveBeenCalledWith(expect.any(Function));
    29→
    30→      const updateFn = mockSet.mock.calls[0][0];
    31→      const newState = updateFn({ airlineMiles: slice.airlineMiles });
    32→
    33→      expect(newState.airlineMiles.isLoading).toBe(true);
    34→    });
    35→
    36→    it('should set redirectURL', () => {
    37→      const url = 'https://vertem.com/marketplace?token=abc';
    38→      slice.airlineMilesActions.setRedirectURL(url);
    39→
    40→      expect(mockSet).toHaveBeenCalledWith(expect.any(Function));
    41→
    42→      const updateFn = mockSet.mock.calls[0][0];
    43→      const newState = updateFn({ airlineMiles: slice.airlineMiles });
    44→
    45→      expect(newState.airlineMiles.redirectURL).toBe(url);
    46→      expect(newState.airlineMiles.isLoading).toBe(false);
    47→      expect(newState.airlineMiles.isError).toBe(false);
    48→    });
    49→
    50→    it('should set error', () => {
    51→      const errorMessage = 'Failed to load';
    52→      slice.airlineMilesActions.setError(errorMessage);
    53→
    54→      expect(mockSet).toHaveBeenCalledWith(expect.any(Function));
    55→
    56→      const updateFn = mockSet.mock.calls[0][0];
    57→      const newState = updateFn({ airlineMiles: slice.airlineMiles });
    58→
    59→      expect(newState.airlineMiles.errorMessage).toBe(errorMessage);
    60→      expect(newState.airlineMiles.isError).toBe(true);
    61→      expect(newState.airlineMiles.isLoading).toBe(false);
    62→    });
    63→
    64→    it('should clear error', () => {
    65→      slice.airlineMilesActions.clearError();
    66→
    67→      expect(mockSet).toHaveBeenCalledWith(expect.any(Function));
    68→
    69→      const updateFn = mockSet.mock.calls[0][0];
    70→      const newState = updateFn({
    71→        airlineMiles: {
    72→          ...slice.airlineMiles,
    73→          isError: true,
    74→          errorMessage: 'some error',
    75→        },
    76→      });
    77→
    78→      expect(newState.airlineMiles.isError).toBe(false);
    79→      expect(newState.airlineMiles.errorMessage).toBe('');
    80→    });
    81→
    82→    it('should reset state', () => {
    83→      slice.airlineMilesActions.reset();
    84→
    85→      expect(mockSet).toHaveBeenCalledWith({
    86→        airlineMiles: {
    87→          redirectURL: '',
    88→          isLoading: false,
    89→          isError: false,
    90→          errorMessage: '',
    91→        },
    92→      });
    93→    });
    94→  });
    95→});
